declare(strict_types=1);require_once dirname(__DIR__,3).'/includes/auth.php';require_once dirname(__DIR__,3).'/includes/conexion.php';require_once dirname(__DIR__,3).'/includes/portal_estudiante.php';exigirRol(['admin']);$defaults=configuracionPortalPredeterminada();$mensaje='';
if(($_SERVER['REQUEST_METHOD']??'')==='POST'){if(!validarTokenCsrf($_POST['csrf_token']??null))$mensaje='La solicitud expiró.';else try{$pdo=obtenerConexion();if(isset($_POST['restaurar'])){$c=(string)$_POST['restaurar'];if(isset($defaults[$c])){$q=$pdo->prepare('UPDATE configuracion_portal_estudiante SET valor=:v WHERE clave=:c');$q->execute(['v'=>$defaults[$c],'c'=>$c]);}$mensaje='Valor predeterminado restaurado.';}else{foreach($defaults as $c=>$f){if(isset($_POST[$c])&&!str_contains($c,'imagen')&&!in_array($c,['portal_logo','avatar_predeterminado'],true)){$q=$pdo->prepare('UPDATE configuracion_portal_estudiante SET valor=:v WHERE clave=:c');$q->execute(['v'=>mb_substr(trim(strip_tags((string)$_POST[$c])),0,500),'c'=>$c]);}}foreach(['login_imagen_fondo'=>'login','login_imagen_lateral'=>'login','registro_imagen_fondo'=>'registro','registro_imagen_lateral'=>'registro','panel_imagen_banner'=>'panel','panel_imagen_fondo'=>'panel','portal_logo'=>'general','avatar_predeterminado'=>'general']as$c=>$g){if(!empty($_FILES[$c]['tmp_name'])){$f=$_FILES[$c];if($f['size']>5242880)throw new RuntimeException('Una imagen supera 5 MB.');$mime=(new finfo(FILEINFO_MIME_TYPE))->file($f['tmp_name']);$ext=['image/jpeg'=>'jpg','image/png'=>'png','image/webp'=>'webp'][$mime]??null;if(!$ext)throw new RuntimeException('Formato no permitido.');$dim=getimagesize($f['tmp_name']);if(!$dim||$dim[0]>8000||$dim[1]>8000)throw new RuntimeException('Dimensiones no permitidas.');$dir=dirname(__DIR__,3).'/uploads/portal-estudiante/'.$g;if(!is_dir($dir))mkdir($dir,0755,true);$name=bin2hex(random_bytes(16)).'.'.$ext;if(!move_uploaded_file($f['tmp_name'],$dir.'/'.$name))throw new RuntimeException('No se pudo guardar la imagen.');$q=$pdo->prepare('UPDATE configuracion_portal_estudiante SET valor=:v WHERE clave=:c');$q->execute(['v'=>'uploads/portal-estudiante/'.$g.'/'.$name,'c'=>$c]);}}$mensaje='Cambios guardados correctamente.';}}catch(Throwable $e){error_log('Admin portal: '.$e->getMessage());$mensaje=$e instanceof RuntimeException?$e->getMessage():'No fue posible guardar.';}}
$GLOBALS['atenea_dashboard_flash']=$mensaje!==''?['type'=>(str_contains($mensaje,'correctamente')||str_contains($mensaje,'restaurado'))?'success':'error','title'=>'Portal del estudiante','message'=>$mensaje]:null;
$cfg=obtenerConexion()->query('SELECT clave,valor FROM configuracion_portal_estudiante')->fetchAll(PDO::FETCH_KEY_PAIR);$dashboardTitle='Portal del estudiante';$dashboardActive='portal-estudiante';require dirname(__DIR__).'/includes/header.php';require dirname(__DIR__).'/partials/_navbar.php';?>
<div class="container-fluid page-body-wrapper"><?php require dirname(__DIR__).'/partials/_sidebar.php';?><div class="main-panel"><div class="content-wrapper"><nav><ol class="breadcrumb"><li class="breadcrumb-item">Gestión del sitio web</li><li class="breadcrumb-item active">Portal del estudiante</li></ol></nav><?php if($mensaje):?><noscript><div class="alert alert-info"><?=atenea_e($mensaje)?></div></noscript><?php endif;?><form method="post" enctype="multipart/form-data"><input type="hidden" name="csrf_token" value="<?=atenea_e(obtenerTokenCsrf())?>"><?php foreach(['login'=>'Inicio de sesión','registro'=>'Registro','panel'=>'Panel del estudiante','general'=>'Imágenes y fondos']as$grupo=>$titulo):?><div class="card mb-4"><div class="card-body"><h2 class="h4"><?=$titulo?></h2><div class="row"><?php foreach($defaults as$c=>$fallback):if(!str_starts_with($c,$grupo.'_')&&!($grupo==='general'&&in_array($c,['portal_logo','avatar_predeterminado','texto_pie_pagina'],true)))continue;$img=str_contains($c,'imagen')||in_array($c,['portal_logo','avatar_predeterminado'],true);?><div class="col-md-6 mb-3"><label class="form-label"><?=atenea_e(str_replace('_',' ',ucfirst($c)))?></label><?php if($img):?><input class="form-control" type="file" name="<?=$c?>" accept=".jpg,.jpeg,.png,.webp"><small><?=atenea_e((string)($cfg[$c]??$fallback))?></small><button class="btn btn-sm btn-outline-secondary d-block mt-2" name="restaurar" value="<?=$c?>">Restaurar imagen predeterminada</button><?php else:?><input class="form-control" name="<?=$c?>" maxlength="500" value="<?=atenea_e((string)($cfg[$c]??$fallback))?>"><?php endif;?></div><?php endforeach;?></div></div></div><?php endforeach;?><button class="btn btn-primary">Guardar cambios</button> <a class="btn btn-outline-primary" target="_blank" href="<?=atenea_url('src/login/sign-in.php')?>">Vista previa</a></form></div><?php require dirname(__DIR__).'/partials/_footer.php';?></div></div><?php require dirname(__DIR__).'/includes/scripts.php';?>
